<template><ion-page><AppHeader /><ion-content class="vivid-page"><div class="page-shell catalog"><h1>Catálogo</h1><AppField v-model="query" placeholder="Buscar por nome ou SKU..." :icon="searchOutline" /><AppState v-if="store.loading" loading title="Sincronizando catálogo" /><AppState v-else-if="!filtered.length" title="Nenhum produto encontrado" /><div v-else class="products"><article v-for="item in filtered" :key="item.id" class="product vivid-card"><img :src="getImageUrl(item.images?.[0])" /><div><h2>{{ item.name }}</h2><p class="tech-label">SKU: {{ item.sku }}</p><strong>{{ money(item.purchasePrice) }}</strong></div><span :class="{danger:item.quantity<=1}" class="stock tech-label">{{ item.quantity }} un</span><div class="actions"><button @click="$router.push(`/products/${item.id}/edit`)"><ion-icon :icon="createOutline" /></button><button @click="remove(item.id)"><ion-icon :icon="trashOutline" /></button></div></article></div><button class="fab" @click="$router.push('/products/add')">+</button></div><BottomNav /></ion-content></ion-page></template>
<script setup lang="ts">import { computed,ref } from 'vue';import { IonPage,IonContent,IonIcon,alertController,onIonViewWillEnter } from '@ionic/vue';import { searchOutline,createOutline,trashOutline } from 'ionicons/icons';import AppHeader from '@/components/AppHeader.vue';import BottomNav from '@/components/BottomNav.vue';import AppField from '@/components/AppField.vue';import AppState from '@/components/AppState.vue';import { useInventoryStore } from '@/stores/inventory';import { getImageUrl } from '@/utils/url';const store=useInventoryStore(),query=ref(''),filtered=computed(()=>store.items.filter(i=>`${i.name} ${i.sku}`.toLowerCase().includes(query.value.toLowerCase()))),money=(v:number)=>v?.toLocaleString('pt-BR',{style:'currency',currency:'BRL'});const remove=async(id:string)=>{const a=await alertController.create({header:'Excluir produto?',buttons:[{text:'Cancelar',role:'cancel'},{text:'Excluir',handler:()=>store.deleteProduct(id)}]});a.present()};onIonViewWillEnter(()=>store.fetchItems());</script>
<style scoped>.catalog h1{font-size:30px;margin:26px 0}.products{display:grid;gap:14px}.product{position:relative;display:grid;grid-template-columns:112px 1fr;gap:16px;padding:16px}.product img{width:112px;height:112px;object-fit:cover;border-radius:12px}.product h2{font-size:18px;margin:2px 0 8px}.product p{font-size:11px;color:var(--vivid-muted)}.product strong{display:block;color:var(--vivid-primary-bright);font-size:22px;margin-top:18px}.stock{position:absolute;right:14px;top:14px;padding:6px 10px;border-radius:20px;background:#4d3157;color:var(--vivid-primary-bright)}.stock.danger{background:#4b2229;color:#ffb4ab}.actions{position:absolute;right:10px;bottom:10px}.actions button{border:0;background:transparent;color:var(--vivid-muted);font-size:20px}.fab{position:fixed;right:22px;bottom:94px;width:58px;height:58px;border:0;border-radius:50%;background:var(--vivid-primary);font-size:34px}</style>
